mapper.select:
select a.id,a.content,a.news_id,a.create_time, case when a.pid =0 then 0 else 1 end as type, b.avatar,b.nickname, d.nickname as be_reply_name, e.title from t_comment a inner join t_user b on a.user_id = b.id left join t_comment c on a.pid = c.id left join t_user d on c.user_id = d.id inner join t_news e on a.news_id = e.id
and a.user_id = #{userId}
and a.news_id = #{newsId}
and b.nickname like concat('%',#{nickname},'%')
and e.title like concat('%',#{title},'%')
order by a.create_time desc limit #{start},#{limit};

select count(a.id) from t_comment a inner join t_user b on a.user_id = b.id left join t_comment c on a.pid = c.id left join t_user d on c.user_id = d.id inner join t_news e on a.news_id = e.id
and a.user_id = #{userId}
and a.news_id = #{newsId}
and b.nickname like concat('%',#{nickname},'%')
and e.title like concat('%',#{title},'%')
